import type { HTMLArkProps } from '@ark-ui/react/factory';
import { ark } from '@ark-ui/react/factory';
import { clsx } from 'clsx';
import { forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './Container.module.css';

export type ContainerSize = 'xs' | 'sm' | 'md' | 'lg' | 'xl' | 'full';
export type ContainerGutter = 'none' | 'sm' | 'md' | 'lg';

export type ContainerRootProps = HTMLArkProps<'div'> & {
  size?: ContainerSize;
  gutter?: ContainerGutter;
};

const ContainerRoot = forwardRef<HTMLDivElement, ContainerRootProps>(function ContainerRoot(
  { size = 'lg', gutter = 'md', className, ...props },
  ref,
) {
  return (
    <ark.div
      ref={ref}
      data-scope="container"
      data-part="root"
      data-slot="container-root"
      data-size={size}
      data-gutter={gutter}
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const Container = Object.assign(ContainerRoot, {
  Root: ContainerRoot,
});

export { Container };

@layer ui.components {
  .root[data-scope='container'][data-part='root'] {
    --container-gutter: var(--container-gutter-md, clamp(1rem, 4vw, 2rem));
    --container-max-width: var(--container-max-width-lg, 72rem);

    box-sizing: border-box;
    display: block;
    width: 100%;
    max-width: calc(var(--container-max-width) + (var(--container-gutter) * 2));
    min-width: 0;
    margin-inline: auto;
    padding-inline: var(--container-gutter);

    &[data-size='xs'] {
      --container-max-width: var(--container-max-width-xs, 40rem);
    }

    &[data-size='sm'] {
      --container-max-width: var(--container-max-width-sm, 48rem);
    }

    &[data-size='md'] {
      --container-max-width: var(--container-max-width-md, 64rem);
    }

    &[data-size='xl'] {
      --container-max-width: var(--container-max-width-xl, 90rem);
    }

    &[data-size='full'] {
      max-width: none;
    }

    &[data-gutter='none'] {
      --container-gutter: 0;
    }

    &[data-gutter='sm'] {
      --container-gutter: var(--container-gutter-sm, clamp(0.75rem, 3vw, 1.5rem));
    }

    &[data-gutter='lg'] {
      --container-gutter: var(--container-gutter-lg, clamp(1.5rem, 5vw, 3rem));
    }
  }
}
